mapper.select:
SELECT rh.id, rh.employee_id, rh.resident_name AS employee_name, d.id AS dormitory_id, d.name AS dormitory_name, rh.room_id, rm.name AS room_number, rh.check_in_date AS checkin_date, DATEDIFF(CURDATE(), rh.check_in_date) AS stay_days, dp.name AS department_name FROM residence_histories rh LEFT JOIN rooms rm ON rm.id = rh.room_id AND rm.deleted_at IS NULL LEFT JOIN dormitories d ON d.id = rm.dormitory_id AND d.deleted_at IS NULL LEFT JOIN departments dp ON dp.id = rh.department_id AND dp.deleted_at IS NULL WHERE rh.deleted_at IS NULL AND rh.check_out_date IS NULL AND DATEDIFF(CURDATE(), rh.check_in_date) >= #{minDays}
AND DATEDIFF(CURDATE(), rh.check_in_date) < #{maxDays}
AND (rh.resident_name LIKE CONCAT('%', #{keyword}, '%') OR rh.employee_id LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY stay_days DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1) FROM residence_histories rh WHERE rh.deleted_at IS NULL AND rh.check_out_date IS NULL AND DATEDIFF(CURDATE(), rh.check_in_date) >= #{minDays}
AND DATEDIFF(CURDATE(), rh.check_in_date) < #{maxDays}
AND (rh.resident_name LIKE CONCAT('%', #{keyword}, '%') OR rh.employee_id LIKE CONCAT('%', #{keyword}, '%'))

SELECT rh.id, rh.resident_name, rh.is_responsible, rh.check_in_date, rh.check_out_date, rh.planned_checkout_date, rh.remarks, d.name AS department_name, r.id AS room_id, r.name AS room_name, dom.id AS dormitory_id, dom.name AS dormitory_name FROM residence_histories rh JOIN rooms r ON r.id = rh.room_id AND r.deleted_at IS NULL JOIN dormitories dom ON dom.id = r.dormitory_id AND dom.deleted_at IS NULL LEFT JOIN regions reg ON reg.id = dom.region_id AND reg.deleted_at IS NULL LEFT JOIN departments d ON d.id = rh.department_id AND d.deleted_at IS NULL WHERE rh.deleted_at IS NULL AND rh.check_in_date <= LAST_DAY(STR_TO_DATE(CONCAT(#{year}, '-', LPAD(#{month}, 2, '0'), '-01'), '%Y-%m-%d')) AND (rh.check_out_date IS NULL OR rh.check_out_date >= STR_TO_DATE(CONCAT(#{year}, '-', LPAD(#{month}, 2, '0'), '-01'), '%Y-%m-%d'))
AND reg.id = #{regionId}
ORDER BY dom.id ASC, r.id ASC, rh.check_in_date ASC

SELECT DATE_FORMAT(rh.check_in_date, '%Y-%m-%d') AS date, 'checkin' AS event_type, COUNT(1) AS cnt FROM residence_histories rh LEFT JOIN rooms rm ON rm.id = rh.room_id AND rm.deleted_at IS NULL LEFT JOIN dormitories d ON d.id = rm.dormitory_id AND d.deleted_at IS NULL LEFT JOIN regions r ON r.id = d.region_id WHERE rh.deleted_at IS NULL AND YEAR(rh.check_in_date) = #{year} AND MONTH(rh.check_in_date) = #{month}
AND r.id = #{regionId}
GROUP BY DATE_FORMAT(rh.check_in_date, '%Y-%m-%d') UNION ALL SELECT DATE_FORMAT(rh.check_out_date, '%Y-%m-%d') AS date, 'checkout' AS event_type, COUNT(1) AS cnt FROM residence_histories rh LEFT JOIN rooms rm ON rm.id = rh.room_id AND rm.deleted_at IS NULL LEFT JOIN dormitories d ON d.id = rm.dormitory_id AND d.deleted_at IS NULL LEFT JOIN regions r ON r.id = d.region_id WHERE rh.deleted_at IS NULL AND rh.check_out_date IS NOT NULL AND YEAR(rh.check_out_date) = #{year} AND MONTH(rh.check_out_date) = #{month}
AND r.id = #{regionId}
GROUP BY DATE_FORMAT(rh.check_out_date, '%Y-%m-%d')
